import{_ as a,o,c as l,a2 as i}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Handbook Content Policy","description":"","frontmatter":{},"headers":[],"relativePath":"practices/handbook-content-policy.md","filePath":"practices/handbook-content-policy.md"}'),t={name:"practices/handbook-content-policy.md"};function d(c,e,r,n,h,p){return o(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="handbook-content-policy" tabindex="-1">Handbook Content Policy <a class="header-anchor" href="#handbook-content-policy" aria-label="Permalink to &quot;Handbook Content Policy&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p>本规则定义 Evolution Handbook 的最小结构和内容质量门槛。</p><h2 id="参与原则" tabindex="-1">参与原则 <a class="header-anchor" href="#参与原则" aria-label="Permalink to &quot;参与原则&quot;">​</a></h2><ul><li>团队所有成员都有权提出补充、修正、反例和废弃建议。</li><li>README、索引、链接和 Draft 不设隐性维护者门槛。</li><li>内容是否合并按影响分级审查，而不是按贡献者职位判断。</li><li>组织 Standard、治理和跨项目约束需要相关 Owner 明确批准。</li><li>不完整但有价值的观察可以先进入 Issue 或 Draft PR。</li></ul><p>具体参与流程见 <a href="./../CONTRIBUTING.html"><code>CONTRIBUTING.md</code></a>。</p><h2 id="目录最小完整性" tabindex="-1">目录最小完整性 <a class="header-anchor" href="#目录最小完整性" aria-label="Permalink to &quot;目录最小完整性&quot;">​</a></h2><p>每个长期存在的子目录应有 <code>README.md</code>，至少说明：</p><ol><li>目录解决什么问题。</li><li>哪些内容应该或不应该进入。</li><li>当前已有文档及其状态。</li><li>新内容的准入条件。</li><li>已知缺口或下一步候选内容。</li></ol><p>目录尚无正式内容时，应明确写“暂无已晋升内容”，不能用空目录暗示存在组织标准。</p><h2 id="文档最小元数据" tabindex="-1">文档最小元数据 <a class="header-anchor" href="#文档最小元数据" aria-label="Permalink to &quot;文档最小元数据&quot;">​</a></h2><p>原则、模式、Playbook、契约、决策和案例应尽量包含：</p><ul><li>状态：<code>Draft</code>、<code>Pattern Candidate</code>、<code>Adopted</code>、<code>Standard</code>、<code>Deprecated</code> 或 <code>Superseded</code></li><li>适用范围与不适用范围</li><li>Owner 或负责角色</li><li>证据、来源或最后核对日期</li><li>验证方式或复审触发条件</li></ul><p>在负责人尚未确定时使用 <code>Owner：待指定</code>，不得猜测个人姓名。</p><h2 id="结构化-metadata" tabindex="-1">结构化 metadata <a class="header-anchor" href="#结构化-metadata" aria-label="Permalink to &quot;结构化 metadata&quot;">​</a></h2><p>契约、决策和项目 Playbook 可使用 YAML frontmatter，基础字段包括：</p><ul><li><code>status</code>：文档或决策当前状态</li><li><code>owner</code>：负责角色、团队或 <code>待指定</code></li><li><code>scope</code>：<code>organization</code>、<code>project</code>、<code>repository</code> 或 <code>domain</code></li><li><code>last_reviewed</code>：最近核对日期</li></ul><p>现有文档可以继续保留 <code>**状态：...**</code> 行，并在复审或实质修改时渐进迁移。metadata 只用于机器索引、复审和漂移检查；状态字段不代表自动晋升，<code>Standard</code> 仍需要相关 Owner 明确批准。</p><h2 id="内容质量" tabindex="-1">内容质量 <a class="header-anchor" href="#内容质量" aria-label="Permalink to &quot;内容质量&quot;">​</a></h2><ul><li>原则解释“为什么”，不堆积具体命令。</li><li>Pattern 说明问题、适用条件、结构和代价。</li><li>Playbook 提供步骤、检查点、失败处理和完成条件。</li><li>Contract 明确 Owner、生产者、消费者、不变量和变更方式。</li><li>Decision 记录背景、选择、替代方案、影响和状态。</li><li>Case Study 同时记录结果、失败与限制。</li><li>Reference 说明采用了什么、没有采用什么，以及最后核对时间。</li></ul><h2 id="新增与复审" tabindex="-1">新增与复审 <a class="header-anchor" href="#新增与复审" aria-label="Permalink to &quot;新增与复审&quot;">​</a></h2><p>新增文档时：</p><ol><li>从 <code>WORKSPACE.md</code> 确认归属。</li><li>更新所在目录的 <code>README.md</code>。</li><li>新增项目或仓库时更新相关项目文档。</li><li>运行本地链接、格式和敏感信息检查。</li></ol><p>编辑性修正可使用轻量 PR。约束性内容还应说明影响范围、Owner、迁移方式和验证证据。</p><p>以下情况触发复审：</p><ul><li>所引用的产品、工具或 API 发生重大版本变化</li><li>实际项目行为与文档冲突</li><li>同一规则出现两个长期真源</li><li>实践连续两次未产生预期结果</li><li>Owner、项目状态或仓库边界变化</li></ul><h2 id="不接受的内容" tabindex="-1">不接受的内容 <a class="header-anchor" href="#不接受的内容" aria-label="Permalink to &quot;不接受的内容&quot;">​</a></h2><ul><li>无来源的“行业最佳实践”列表</li><li>未脱敏的内部数据和本机信息</li><li>从其他仓库整篇复制的实现文档</li><li>没有退出条件的临时兼容方案</li><li>只有宣传结论、没有证据和限制的案例</li></ul>',28)])])}const b=a(t,[["render",d]]);export{u as __pageData,b as default};
